package main
import "fmt"
func main() {
	var qnt int
	fmt.Scan(&qnt)

	// Cria um mapa para contar quantas vezes cada animal aparece
	contagem := make(map[int]int)
	for i := 0; i < qnt; i++ {
		var animal int
		fmt.Scan(&animal)
		// Incrementa a quantidade desse animal no mapa
		contagem[animal]++
	}

	casais := 0

	for especie, qtdMachos := range contagem {
		if especie > 0 {
			qtdFemeas := contagem[-especie]

			// O número de casais possíveis é o menor valor
			// entre a quantidade de machos e de fêmeas

			if qtdMachos < qtdFemeas {

				// Há menos machos que fêmeas
				// Então todos os machos formam casal
				casais += qtdMachos

			} else {

				// Há menos fêmeas que machos
				// Então todas as fêmeas formam casal
				casais += qtdFemeas
			}
		}
	}

	// Exibe o total de casais encontrados
	fmt.Println(casais)
}
